#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        long long *A = (long long*)malloc(N*sizeof(long long));
        long long *B = (long long*)malloc(N*sizeof(long long));
        long long sumA=0,sumB=0,ans=0;
        for(int i=0;i<N;i++){ scanf("%lld",&A[i]); sumA+=A[i]; }
        for(int i=0;i<N;i++){ scanf("%lld",&B[i]); sumB+=B[i]; }
        if(sumA!=sumB){
            printf("-1\n");
        }else{
            for(int i=0;i<N;i++) if(B[i]>A[i]) ans+=B[i]-A[i];
            printf("%lld\n",ans);
        }
        free(A); free(B);
    }
    return 0;
}

