import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            long[] A = new long[N];
            long[] B = new long[N];
            long sumA = 0, sumB = 0, ans = 0;
            for (int i = 0; i < N; i++) { A[i] = fs.nextLong(); sumA += A[i]; }
            for (int i = 0; i < N; i++) { B[i] = fs.nextLong(); sumB += B[i]; }
            if (sumA != sumB) {
                sb.append(-1).append('\n');
            } else {
                for (int i = 0; i < N; i++) if (B[i] > A[i]) ans += B[i] - A[i];
                sb.append(ans).append('\n');
            }
        }
        System.out.print(sb.toString());
    }
    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException { return Long.parseLong(next()); }
        int nextInt() throws IOException { return Integer.parseInt(next()); }
        String next() throws IOException {
            StringBuilder sb = new StringBuilder();
            int c;
            while ((c = readByte()) != -1 && c <= ' ') {}
            if (c == -1) return "";
            do { sb.append((char)c); } while ((c = readByte()) != -1 && c > ' ');
            return sb.toString();
        }
    }
}

